### 2. **Safe Implementation: WeakRef Pool + GC Pressure Cleanup**
Node 14+ WeakRefs + 18+ Finalizers. Ties to V8 via `beforeGC`/`afterGC` events (proxy `v8` APIs).

```js
const sharp = require('sharp');
sharp.cache({ memory: 0, files: 0 }); // Disable built-in cache
sharp.concurrency(4); // Global threads

class SharpPool {
  constructor(maxSize = 8) { // Tune to CPU cores * 2
    this.pool = new Set();
    this.weakRefs = new Set(); // Track for finalization
    this.maxSize = maxSize;
    this.checkoutCount = 0;

    // Heap pressure thresholds (tune via your heap snapshots)
    this.highPressure = 1.2e9; // 1.2GB heap trigger
    this.gcCleanupDelay = 100; // ms post-GC

    this.setupGCNotifier();
  }

  setupGCNotifier() {
    // V8 GC callbacks (Node 12+)
    const beforeGC = () => {
      console.log('High pressure: Pre-GC pool trim');
      this.trimTo(2); // Shrink aggressively
    };

    if (typeof global.gc === 'function') {
      // --expose-gc mode
      const interval = setInterval(() => {
        if (process.memoryUsage().heapUsed > this.highPressure) {
          global.gc();
          setTimeout(() => this.evictStale(), this.gcCleanupDelay);
        }
      }, 1000);

      process.on('SIGUSR2', () => { // Manual GC trigger
        global.gc();
        this.evictStale();
      });
    }

    // WeakRef Finalizer (Node 18+)
    if (typeof FinalizationRegistry !== 'undefined') {
      this.registry = new FinalizationRegistry((inst) => {
        console.log('Finalized Sharp:', inst);
        inst.destroy();
      });
    }

    // Poll for older Node
    setInterval(() => this.evictStale(), 5000);
  }

  acquire() {
    this.checkoutCount++;

    // Return pooled if avail
    for (let ref of this.weakRefs) {
      const inst = ref.deref();
      if (inst && !inst.destroyed) { // Sharp has no 'destroyed' flag? Check err on use
        this.weakRefs.delete(ref);
        return inst.clone(); // Fresh clone for safety (libvips graph)
      }
    }

    // Create new if under max
    if (this.pool.size < this.maxSize) {
      const inst = sharp();
      const weakRef = new WeakRef(inst);
      this.weakRefs.add(weakRef);
      if (this.registry) this.registry.register(inst, inst);
      return inst;
    }

    throw new Error('Pool exhausted - scale up');
  }

  release(inst) {
    // Reset for reuse (clear input/metadata)
    inst.reset(); // Sharp method? Or chain .toBuffer() noop
    this.weakRefs.add(new WeakRef(inst));
  }

  trimTo(minSize) {
    // Evict excess
    while (this.weakRefs.size > minSize) {
      const ref = this.weakRefs.values().next().value;
      const inst = ref?.deref();
      if (!inst) {
        this.weakRefs.delete(ref);
      } else {
        inst.destroy();
      }
    }
  }

  evictStale() {
    this.weakRefs.forEach((ref, set) => {
      if (!ref.deref()) set.delete(ref);
    });
    this.trimTo(Math.floor(this.maxSize * 0.5));
  }
}

// Usage in Bull job
const pool = new SharpPool(8);

uploadQueue.process('process-image', async (job) => {
  let sharpInst = null;
  try {
    sharpInst = pool.acquire();
    const { filePath } = job.data;

    await sharpInst
      .input(fs.createReadStream(filePath)) // Stream input
      .resize(1024)
      .toFile('/output.jpg');

  } catch (err) {
    job.failed(err);
  } finally {
    if (sharpInst) {
      pool.release(sharpInst); // Return to pool
      sharpInst = null;
    }
    // Input cleanup...
  }
});
```

**Key Safety**:
- **Clone/Reset**: Each acquire gets a "fresh" instance via `clone()` or reset metadata.
- **Heap Pressure**: Auto-trims on `heapUsed > threshold`.
- **Finalizers**: Native destroy on WeakRef GC.
- **Exhaust Fallback**: Throw to fail-fast.
- Run with `--expose-gc --max-old-space-size=4096`.

