class LRUSharpPool {
  // ... (constructor, setupPressureMonitor, trim, evictStale, stats, close unchanged)

  async acquire() {
    this.accessCount++;

    // LRU promote
    const now = Date.now();
    for (const [key, ref] of this.map) {
      const inst = ref.deref();
      if (inst && this.isUsable(inst)) {
        this.map.delete(key);
        this.map.set(now, new WeakRef(inst)); // Refresh LRU
        if (this.registry) this.registry.register(inst, inst);
        return inst; // NO CLONE: Direct base reuse
      }
    }

    // New base sharp()
    if (this.map.size < this.maxSize) {
      const inst = sharp(); // Empty base: fast init
      const weakRef = new WeakRef(inst);
      this.map.set(now, weakRef);
      if (this.registry) this.registry.register(inst, inst);
      return inst;
    }

    this.trim(8);
    return this.acquire();
  }

  release(inst, inputStream = null) {
    if (inputStream) {
      inputStream.destroy(); // Close source
      inputStream = null;
    }
    // Detach: Clear workspace/input (Sharp internal, but safe per src)
    try {
      inst.removeWorkspace?.(); // Nulls buffers/metadata
      // Fallback: Force metadata refresh (cheap)
      inst.metadata().catch(() => {}); // Ignores errors
    } catch (e) {
      console.warn('Detach failed:', e.message);
    }
  }

  isUsable(inst) {
    try {
      // Quick check: No error on empty metadata
      return !!inst.metadata().then(() => true).catch(() => false);
    } catch {
      return false;
    }
  }
}
